from autogen import AssistantAgent, UserProxyAgent

# LLM configuration for the assistant
llm_config = {
    "config_list": [
        {
            "model": "gpt-4o",
            "api_key": "YOUR_OPENAI_API_KEY",  # use os.environ in production
        }
    ],
    "temperature": 0,
    "timeout": 120,
}

# 1. Create the AssistantAgent (LLM-powered, generates code and reasoning)
assistant = AssistantAgent(
    name="assistant",
    llm_config=llm_config,
    system_message=(
        "You are a helpful AI assistant. Solve tasks by writing Python code. "
        "When the task is complete, end your reply with the word TERMINATE."
    ),
)

# 2. Create the UserProxyAgent (automated executor — no human in the loop)
user_proxy = UserProxyAgent(
    name="user_proxy",
    human_input_mode="NEVER",          # fully automated; no human prompt
    code_execution_config={
        "work_dir": "coding",          # directory where code files are saved
        "use_docker": False,           # set True in production for sandboxing
    },
    max_consecutive_auto_reply=5,      # stop after 5 auto-replies to prevent loops
    is_termination_msg=lambda msg: "TERMINATE" in msg.get("content", ""),
)

# 3. Initiate the conversation — the two agents converse until termination
user_proxy.initiate_chat(
    assistant,
    message=(
        "Write a Python function to compute Fibonacci numbers using memoisation "
        "and test it with inputs [0, 1, 5, 10, 20]. Print the results."
    ),
)
